CREATE TYPE "KnowledgeSourceStatus" AS ENUM ('DRAFT','ACTIVE','PAUSED','ERROR','ARCHIVED');
CREATE TYPE "KnowledgeVisibility" AS ENUM ('ORGANIZATION','RESTRICTED','PRIVATE');
CREATE TYPE "KnowledgeIndexStatus" AS ENUM ('PENDING','RUNNING','COMPLETED','FAILED','CANCELLED');
CREATE TABLE "KnowledgeSource" ("id" TEXT PRIMARY KEY,"organizationId" TEXT NOT NULL,"name" TEXT NOT NULL,"type" TEXT NOT NULL,"status" "KnowledgeSourceStatus" NOT NULL DEFAULT 'DRAFT',"configuration" JSONB NOT NULL DEFAULT '{}',"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL);
CREATE UNIQUE INDEX "KnowledgeSource_organizationId_name_key" ON "KnowledgeSource"("organizationId","name");
CREATE INDEX "KnowledgeSource_organizationId_status_type_idx" ON "KnowledgeSource"("organizationId","status","type");
CREATE TABLE "KnowledgeDocument" ("id" TEXT PRIMARY KEY,"organizationId" TEXT NOT NULL,"sourceId" TEXT NOT NULL,"externalId" TEXT NOT NULL,"title" TEXT NOT NULL,"documentType" TEXT NOT NULL,"language" TEXT NOT NULL DEFAULT 'en',"visibility" "KnowledgeVisibility" NOT NULL DEFAULT 'ORGANIZATION',"allowedUserIds" TEXT[] NOT NULL,"metadata" JSONB NOT NULL DEFAULT '{}',"checksum" TEXT NOT NULL,"version" INTEGER NOT NULL DEFAULT 1,"indexedAt" TIMESTAMP(3),"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL,CONSTRAINT "KnowledgeDocument_sourceId_fkey" FOREIGN KEY ("sourceId") REFERENCES "KnowledgeSource"("id") ON DELETE CASCADE);
CREATE UNIQUE INDEX "KnowledgeDocument_organizationId_sourceId_externalId_key" ON "KnowledgeDocument"("organizationId","sourceId","externalId");
CREATE INDEX "KnowledgeDocument_organizationId_documentType_visibility_idx" ON "KnowledgeDocument"("organizationId","documentType","visibility");
CREATE TABLE "KnowledgeChunk" ("id" TEXT PRIMARY KEY,"organizationId" TEXT NOT NULL,"documentId" TEXT NOT NULL,"position" INTEGER NOT NULL,"content" TEXT NOT NULL,"tokenCount" INTEGER NOT NULL,"metadata" JSONB NOT NULL DEFAULT '{}',"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,CONSTRAINT "KnowledgeChunk_documentId_fkey" FOREIGN KEY ("documentId") REFERENCES "KnowledgeDocument"("id") ON DELETE CASCADE);
CREATE UNIQUE INDEX "KnowledgeChunk_documentId_position_key" ON "KnowledgeChunk"("documentId","position");
CREATE TABLE "KnowledgeEmbedding" ("id" TEXT PRIMARY KEY,"organizationId" TEXT NOT NULL,"chunkId" TEXT NOT NULL,"provider" TEXT NOT NULL,"model" TEXT NOT NULL,"dimension" INTEGER NOT NULL,"vector" DOUBLE PRECISION[] NOT NULL,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,CONSTRAINT "KnowledgeEmbedding_chunkId_fkey" FOREIGN KEY ("chunkId") REFERENCES "KnowledgeChunk"("id") ON DELETE CASCADE);
CREATE UNIQUE INDEX "KnowledgeEmbedding_chunkId_key" ON "KnowledgeEmbedding"("chunkId");
CREATE TABLE "KnowledgeIndexJob" ("id" TEXT PRIMARY KEY,"organizationId" TEXT NOT NULL,"sourceId" TEXT NOT NULL,"status" "KnowledgeIndexStatus" NOT NULL DEFAULT 'PENDING',"requestedByUserId" TEXT NOT NULL,"documentCount" INTEGER NOT NULL DEFAULT 0,"chunkCount" INTEGER NOT NULL DEFAULT 0,"errorMessage" TEXT,"completedAt" TIMESTAMP(3),"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL,CONSTRAINT "KnowledgeIndexJob_sourceId_fkey" FOREIGN KEY ("sourceId") REFERENCES "KnowledgeSource"("id") ON DELETE CASCADE);
CREATE TABLE "KnowledgeQueryAudit" ("id" TEXT PRIMARY KEY,"organizationId" TEXT NOT NULL,"userId" TEXT NOT NULL,"query" TEXT NOT NULL,"resultCount" INTEGER NOT NULL,"topScore" DOUBLE PRECISION NOT NULL,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);
